def verify(output: str):
    # Initialize tracking variables
    constraints_satisfied = 0
    total_constraints = 5
    failures = []

    # Check 1: String contains exactly 1 occurrence of substring "2026"
    count_2026 = output.count("2026")
    if count_2026 == 1:
        constraints_satisfied += 1
    else:
        failures.append(f"substring '2026' appears {count_2026} times (expected 1)")

    # Check 2: String contains no occurrence of "000"
    count_000 = output.count("000")
    if count_000 == 0:
        constraints_satisfied += 1
    else:
        failures.append(f"substring '000' appears {count_000} times (expected 0)")

    # Check 3: String must not start with '0'
    if output[0] != '0':
        constraints_satisfied += 1
    else:
        failures.append("string starts with '0'")

    # Check 4: String must end with an odd digit (1,3,5,7,9)
    if output[-1] in '13579':
        constraints_satisfied += 1
    else:
        failures.append(f"string ends with '{output[-1]}' (expected odd digit)")

    # Check 5: Total number of even digits (0,2,4,6,8) is exactly 10
    even_digits = '02468'
    even_count = sum(1 for digit in output if digit in even_digits)
    if even_count == 10:
        constraints_satisfied += 1
    else:
        failures.append(f"even digits count is {even_count} (expected 10)")

    # Calculate score
    score = constraints_satisfied / total_constraints
    is_valid = constraints_satisfied == total_constraints

    # Build message
    if is_valid:
        message = "All constraints satisfied."
    else:
        message = "Failed constraints: " + "; ".join(failures)

    return (is_valid, score, message)
